const body = $input.first().json.body || $input.first().json;

return [{
  json: {
    customer_id:       body.customer_id    || `K-${Date.now()}`,
    trigger:           body.trigger        || 'segment_analysis',
    segment:           body.segment        || 'Privat',
    existing_products: body.products       || [],
    annual_premium_chf: parseFloat(body.annual_premium || 0),
    product_gaps:      body.gaps           || [],
    renewal_date:      body.renewal_date   || null,
    last_offer_date:   body.last_offer     || null,
    offers_ytd:        parseInt(body.offers_ytd || 0),
    received_at:       new Date().toISOString()
  }
}];

const agent   = $input.first().json;
const context = $('Normalize Offer Context').first().json;

const crossSellScore = agent.cross_sell_score || 0;
const offerValue     = agent.offer_value_chf  || 0;
const confidence     = agent.confidence       || 0.5;
const offersYtd      = context.offers_ytd     || 0;

// Business rules
let route, urgency;

// Policy: max 2 offers per customer per quarter
if (offersYtd >= 2 || offerValue > 1500) {
  route   = 'human_review';   // Needs approval
  urgency = offerValue > 3000 ? 'high' : 'medium';
} else if (crossSellScore >= 0.7 && confidence >= 0.75) {
  route   = 'automation';     // Auto-send
  urgency = 'low';
} else {
  route   = 'human_review';   // Low confidence — human check
  urgency = 'low';
}

return [{
  json: {
    ...context,
    product:          agent.recommended_product || 'Zusatzprodukt',
    offer_value_chf:  offerValue,
    cross_sell_score: crossSellScore,
    confidence:       confidence,
    route:            route,
    urgency:          urgency,
    title:  `Angebot: ${agent.recommended_product || 'generiert'}`,
    detail: `${context.segment} · Cross-Sell ${(crossSellScore*100).toFixed(0)}% · CHF ${offerValue.toLocaleString('de-CH')}`,
    agent_latency_ms: agent.latency_ms || null
  }
}];
